import http from "../http-common";
import authHeader from "./auth-header";

const chat = (message) => {
  return http.post("/agent/chat", { message }, { headers: authHeader() });
};

const getTools = () => {
  return http.get("/agent/tools", { headers: authHeader() });
};

const AgentService = {
  chat,
  getTools,
};

export default AgentService;
